const lineData = $input.first().json;
const events = lineData.events || [];
const event = events[0];
if (!event) return [{ json: { valid: false, errorMessage: 'イベントなし' } }];
const userId = event.source?.userId || '';
const replyToken = event.replyToken || '';
const msgType = event.message?.type || '';
const msgText = (event.message?.text || '').trim();
const now = new Date();
const jst = new Date(now.getTime() + 9 * 3600000);
const y = jst.getFullYear(), mo = jst.getMonth() + 1;
const dd = String(jst.getDate()).padStart(2,'0');
const today = `${y}/${String(mo).padStart(2,'0')}/${dd}`;
const defaultFile = `経営管理_${y}年${mo}月.xlsx`;

if (msgType === 'image' || msgType === 'file') {
  return [{ json: { valid: true, messageType: 'file_pending', userId, replyToken,
    messageId: event.message.id, fileType: msgType, fileName: defaultFile, targetYear: y, targetMonth: mo } }];
}
if (msgType !== 'text') {
  return [{ json: { valid: false, replyToken, errorMessage: 'テキストまたは画像・PDFのみ対応しています' } }];
}
if (msgText === 'ヘルプ' || msgText === 'help') {
  return [{ json: { valid: true, messageType: 'query_help', userId, replyToken,
    fileName: defaultFile, targetYear: y, targetMonth: mo } }];
}

const claudeKey = 'YOUR_CLAUDE_API_KEY';

const prompt = `今日は${today}です。以下のメッセージを解析しJSONのみ返答。

メッセージ:「${msgText}」

分類:
- expense: 経費（現金払い・小口経費）
- subcontractor_payment: 外注業者への支払い記録
- sales: 売上・請求登録
- payment_received: 売上の入金記録
- query: 照会（未払い/未入金/サマリー/粗利/支払期限）
- unknown: 不明

経費種別: 材料費/燃料費/高速料金/駐車場代/工具・消耗品費/通信費/交際費/会議費/事務用品費/広告宣伝費/研修費/福利厚生費/車両維持費/地代家賃/保険料/雑費

返答例:
expense: {"messageType":"expense","date":"${today}","expenseCategory":"材料費","paymentMethod":"現金","storeName":"○○電機","projectName":"","amount":5000,"note":""}
subcontractor_payment: {"messageType":"subcontractor_payment","vendorName":"梶原通信","paymentAmount":55000,"paymentDate":"${today}"}
sales: {"messageType":"sales","registrationDate":"${today}","clientName":"港振興業株式会社","projectName":"△△工事","amountExTax":100000,"tax":10000,"totalAmount":110000,"invoiceDate":"${today}","paymentDueDate":"2026/05/31"}
payment_received: {"messageType":"payment_received","clientName":"港振興業株式会社","receivedAmount":110000,"receivedDate":"${today}"}
query: {"messageType":"query","queryType":"未払い確認"}
queryType候補: 未払い確認/未入金確認/今月サマリー/粗利確認/支払期限確認`;

const res = await this.helpers.httpRequest({
  method: 'POST', url: 'https://api.anthropic.com/v1/messages',
  headers: { 'x-api-key': claudeKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: { model: 'claude-haiku-4-5-20251001', max_tokens: 400,
    messages: [{ role: 'user', content: prompt }] },
  json: true
});
let parsed;
try {
  const txt = res.content[0].text.trim();
  parsed = JSON.parse((txt.match(/\{[\s\S]*\}/) || [txt])[0]);
} catch(e) {
  return [{ json: { valid: false, replyToken, errorMessage: 'メッセージを解析できませんでした。再送してください。' } }];
}
if (parsed.messageType === 'unknown') {
  return [{ json: { valid: false, replyToken, errorMessage: '内容を認識できませんでした。\n「ヘルプ」で使い方を確認できます。' } }];
}
const ds = parsed.date || parsed.registrationDate || today;
const dp = ds.split('/');
const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
return [{ json: { valid: true, ...parsed, userId, replyToken,
  fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];

const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('LINEメッセージ解析').first().json;
  const fileInfo = $('月次ファイル情報取得').first().json;
  try {
    const wb = new ExcelJS.Workbook();
    const dlUrl = fileInfo['@microsoft.graph.downloadUrl'];
    if (dlUrl) {
      try {
        const r = await this.helpers.httpRequest({ method:'GET', url:dlUrl, encoding:'arraybuffer', returnFullResponse:false });
        await wb.xlsx.load(Buffer.from(r), { useSharedStrings: false });
      } catch(e) {}
    }
    const toDate = s => { if(!s)return null; const p=s.split('/'); return new Date(Date.UTC(+p[0],+p[1]-1,+p[2])); };
    const getV = c => (c&&typeof c==='object'&&'result'in c)?c.result:c;
    const ensure = (name, hdrs) => {
      let s = wb.getWorksheet(name);
      if (!s) { s=wb.addWorksheet(name); const h=s.getRow(1); hdrs.forEach((v,i)=>h.getCell(i+1).value=v); h.font={bold:true}; h.commit(); }
      return s;
    };
    const lastR = (s, col) => { let r=1; s.eachRow((row,n)=>{ if(n>=2&&getV(row.getCell(col).value)!=null&&getV(row.getCell(col).value)!=='')r=n; }); return r; };
    const mt = data.messageType;

    if (mt === 'expense') {
      const s = ensure('経費', ['No','日付','経費種類','支払方法','店名・支払先','案件名','金額（税込）','備考']);
      const nr = lastR(s,2)+1; const row = s.getRow(nr);
      row.getCell(1).value=nr-1;
      row.getCell(2).value=toDate(data.date); row.getCell(2).numFmt='YYYY/MM/DD';
      row.getCell(3).value=data.expenseCategory; row.getCell(4).value=data.paymentMethod;
      row.getCell(5).value=data.storeName; row.getCell(6).value=data.projectName||'';
      row.getCell(7).value=data.amount; row.getCell(7).numFmt='#,##0';
      row.getCell(8).value=data.note||''; row.commit();

    } else if (mt === 'subcontractor_payment') {
      const s = ensure('外注管理', ['No','登録日','業者名','種別','インボイス','案件名','請求額(税抜)','消費税(10%)','合計(税込)','請求日','支払期限','支払日','支払額','状況']);
      let target = null;
      s.eachRow((row,n)=>{ if(n<2||target)return; if(getV(row.getCell(3).value)===data.vendorName&&getV(row.getCell(14).value)==='未払')target=row; });
      if (!target) return [{ json: { valid:false, replyToken:data.replyToken, errorMessage:`${data.vendorName}の未払い請求が見つかりません` } }];
      target.getCell(12).value=toDate(data.paymentDate); target.getCell(12).numFmt='YYYY/MM/DD';
      target.getCell(13).value=data.paymentAmount; target.getCell(13).numFmt='#,##0';
      target.getCell(14).value='支払済'; target.commit();

    } else if (mt === 'sales') {
      const s = ensure('売上管理', ['No','登録日','得意先名','案件名','請求額(税抜)','消費税(10%)','合計(税込)','請求日','入金期限','入金日','入金額','状況']);
      const nr = lastR(s,2)+1; const row = s.getRow(nr);
      row.getCell(1).value=nr-1;
      row.getCell(2).value=toDate(data.registrationDate); row.getCell(2).numFmt='YYYY/MM/DD';
      row.getCell(3).value=data.clientName; row.getCell(4).value=data.projectName||'';
      row.getCell(5).value=data.amountExTax; row.getCell(5).numFmt='#,##0';
      row.getCell(6).value=data.tax; row.getCell(6).numFmt='#,##0';
      row.getCell(7).value=data.totalAmount; row.getCell(7).numFmt='#,##0';
      row.getCell(8).value=toDate(data.invoiceDate); row.getCell(8).numFmt='YYYY/MM/DD';
      if(data.paymentDueDate){row.getCell(9).value=toDate(data.paymentDueDate); row.getCell(9).numFmt='YYYY/MM/DD';}
      row.getCell(12).value='未入金'; row.commit();

    } else if (mt === 'payment_received') {
      const s = ensure('売上管理', ['No','登録日','得意先名','案件名','請求額(税抜)','消費税(10%)','合計(税込)','請求日','入金期限','入金日','入金額','状況']);
      let target = null;
      s.eachRow((row,n)=>{ if(n<2||target)return; if(getV(row.getCell(3).value)===data.clientName&&getV(row.getCell(12).value)==='未入金')target=row; });
      if (!target) return [{ json: { valid:false, replyToken:data.replyToken, errorMessage:`${data.clientName}の未入金請求が見つかりません` } }];
      target.getCell(10).value=toDate(data.receivedDate); target.getCell(10).numFmt='YYYY/MM/DD';
      target.getCell(11).value=data.receivedAmount; target.getCell(11).numFmt='#,##0';
      target.getCell(12).value='入金済'; target.commit();
    }

    // 月次サマリー更新
    const summary = wb.getWorksheet('月次サマリー');
    if (summary) {
      const getV2 = c => (c&&typeof c==='object'&&'result'in c)?c.result:c;
      const expS=wb.getWorksheet('経費'), subS=wb.getWorksheet('外注管理'), salS=wb.getWorksheet('売上管理');
      const expCats=['材料費','燃料費','高速料金','駐車場代','工具・消耗品費','通信費','交際費','会議費','事務用品費','広告宣伝費','研修費','福利厚生費','車両維持費','地代家賃','保険料','雑費'];
      const byCat={};
      if(expS)expS.eachRow((r,n)=>{ if(n<2)return; const c=getV2(r.getCell(3).value); const a=getV2(r.getCell(7).value)||0; if(c)byCat[c]=(byCat[c]||0)+a; });
      const expTotal=Object.values(byCat).reduce((a,b)=>a+b,0);
      let salTotal=0,recvTotal=0;
      if(salS)salS.eachRow((r,n)=>{ if(n<2)return; const t=getV2(r.getCell(7).value)||0; const st=getV2(r.getCell(12).value); salTotal+=t; if(st==='入金済')recvTotal+=(getV2(r.getCell(11).value)||t); });
      let subTotal=0,subPaid=0;
      if(subS)subS.eachRow((r,n)=>{ if(n<2)return; const t=getV2(r.getCell(9).value)||0; const st=getV2(r.getCell(14).value); subTotal+=t; if(st==='支払済')subPaid+=(getV2(r.getCell(13).value)||t); });
      const grossProfit=salTotal-subTotal-expTotal;
      const cm={'請求済合計（税込）':salTotal,'入金済合計':recvTotal,'未入金残高':salTotal-recvTotal,
        '請求受取合計（税込）':subTotal,'支払済合計':subPaid,'未払残高':subTotal-subPaid,
        '経費合計':expTotal,'■ 粗利（概算）':grossProfit};
      expCats.forEach(c=>cm[c]=byCat[c]||0);
      summary.eachRow(row=>{ const lb=String(getV2(row.getCell(1).value)||''); if(cm[lb]!==undefined){row.getCell(2).value=cm[lb]; row.getCell(2).numFmt='#,##0'; row.commit(); } });
    }

    // OneDriveアップロード
    const creds = await this.getCredentials('microsoftDriveOAuth2Api');
    const token = creds.oauthTokenData?.access_token;
    if (!token) throw new Error('Microsoft認証トークンが取得できません。資格情報を再接続してください。');
    const buf = await wb.xlsx.writeBuffer({ useSharedStrings: false });
    const upUrl = fileInfo.id
      ? `https://graph.microsoft.com/v1.0/me/drive/items/${fileInfo.id}/content`
      : `https://graph.microsoft.com/v1.0/me/drive/root:/業務管理システム/経費管理/月次/${data.fileName}:/content`;
    await this.helpers.httpRequest({
      method:'PUT', url:upUrl,
      headers:{ 'Authorization':`Bearer ${token}`, 'Content-Type':'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' },
      body:Buffer.from(buf), returnFullResponse:false
    });
    return [{ json: { ...data, valid: true } }];
  } catch(e) {
    return [{ json: { valid:false, replyToken:data.replyToken, errorMessage:e.message } }];
  }
})();

const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('LINEメッセージ解析').first().json;
  const replyToken = data.replyToken;
  const fmt = n => (n||0).toLocaleString('ja-JP');

  if (data.messageType === 'query_help') {
    const msg = `【経営管理システム 使い方】\n\n📝 テキスト入力:\n経費 → 「経費 材料費 5000円 現金」\n外注支払 → 「外注支払 梶原通信 55000円」\n売上登録 → 「売上 港振興業 △△工事 100000円」\n入金記録 → 「入金 港振興業 110000円」\n\n📄 PDF/画像送信:\n給与明細・請求書・クレカ明細は写真またはPDFで送信\n\n🔍 照会:\n未払い確認\n未入金確認\n今月サマリー\n粗利確認\n支払期限確認\nヘルプ`;
    return [{ json: { replyToken, replyMessage: msg } }];
  }

  const fileInfo = $('月次ファイル情報取得（照会）').first().json;
  const dlUrl = fileInfo['@microsoft.graph.downloadUrl'];
  if (!dlUrl) {
    return [{ json: { replyToken, replyMessage: '今月のデータがまだありません。' } }];
  }
  const wb = new ExcelJS.Workbook();
  const res = await this.helpers.httpRequest({ method:'GET', url:dlUrl, encoding:'arraybuffer', returnFullResponse:false });
  await wb.xlsx.load(Buffer.from(res), { useSharedStrings: false });
  const getV = c => (c&&typeof c==='object'&&'result'in c)?c.result:c;
  const dateStr = d => { if(!(d instanceof Date))return d||''; return `${d.getFullYear()}/${String(d.getMonth()+1).padStart(2,'0')}/${String(d.getDate()).padStart(2,'0')}`; };
  const qt = data.queryType;

  if (qt === '未払い確認') {
    const s = wb.getWorksheet('外注管理');
    if (!s) return [{ json: { replyToken, replyMessage: '外注管理データがありません。' } }];
    const list = [];
    s.eachRow((row,n)=>{ if(n<2)return; const v=getV(row.getCell(3).value),st=getV(row.getCell(14).value); if(v&&st==='未払'){const a=getV(row.getCell(9).value)||0,dd=dateStr(getV(row.getCell(11).value));list.push(`${v}\n  ¥${fmt(a)}  期限:${dd||'未設定'}`);} });
    return [{ json: { replyToken, replyMessage: list.length>0?`【未払い一覧】\n\n${list.join('\n\n')}\n\n計${list.length}件`:'✅ 未払いはありません' } }];
  }

  if (qt === '未入金確認') {
    const s = wb.getWorksheet('売上管理');
    if (!s) return [{ json: { replyToken, replyMessage: '売上管理データがありません。' } }];
    const list = [];
    s.eachRow((row,n)=>{ if(n<2)return; const c=getV(row.getCell(3).value),st=getV(row.getCell(12).value); if(c&&st==='未入金'){const a=getV(row.getCell(7).value)||0,dd=dateStr(getV(row.getCell(9).value));list.push(`${c}\n  ¥${fmt(a)}  期限:${dd||'未設定'}`);} });
    return [{ json: { replyToken, replyMessage: list.length>0?`【未入金一覧】\n\n${list.join('\n\n')}\n\n計${list.length}件`:'✅ 未入金はありません' } }];
  }

  if (qt === '今月サマリー' || qt === '粗利確認') {
    const s = wb.getWorksheet('月次サマリー');
    if (!s) return [{ json: { replyToken, replyMessage: 'サマリーデータがありません。' } }];
    const vals = {};
    s.eachRow(row=>{ const lb=String(getV(row.getCell(1).value)||''); const v=getV(row.getCell(2).value)||0; if(lb&&!lb.startsWith('月次'))vals[lb]=v; });
    const msg = `【今月サマリー】\n\n■ 売上\n請求済: ¥${fmt(vals['請求済合計（税込）'])}\n入金済: ¥${fmt(vals['入金済合計'])}\n未入金: ¥${fmt(vals['未入金残高'])}\n\n■ 外注費\n請求受取: ¥${fmt(vals['請求受取合計（税込）'])}\n支払済: ¥${fmt(vals['支払済合計'])}\n未払: ¥${fmt(vals['未払残高'])}\n\n■ 経費\n合計: ¥${fmt(vals['経費合計'])}\n\n■ 粗利（概算）\n¥${fmt(vals['■ 粗利（概算）']||0)}`;
    return [{ json: { replyToken, replyMessage: msg } }];
  }

  if (qt === '支払期限確認') {
    const s = wb.getWorksheet('外注管理');
    if (!s) return [{ json: { replyToken, replyMessage: '外注管理データがありません。' } }];
    const now = new Date(); const limit = new Date(now.getTime()+7*86400000);
    const list = [];
    s.eachRow((row,n)=>{ if(n<2)return; const v=getV(row.getCell(3).value),st=getV(row.getCell(14).value),dd=getV(row.getCell(11).value); if(v&&st==='未払'&&dd instanceof Date&&dd<=limit){const a=getV(row.getCell(9).value)||0;list.push(`${v}\n  ¥${fmt(a)}  期限:${dateStr(dd)}`);} });
    return [{ json: { replyToken, replyMessage: list.length>0?`【支払期限（1週間以内）】\n\n${list.join('\n\n')}\n\n計${list.length}件`:'✅ 1週間以内の支払期限はありません' } }];
  }

  return [{ json: { replyToken, replyMessage: '照会コマンドが認識できませんでした。\n「ヘルプ」で確認してください。' } }];
})();

